insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('deep-001', 'Did you feel at peace today?', 'peace', 2, 'Peace here means calm and settled — it doesn''t have to mean happy.', ARRAY['peace', 'emotions', 'mindfulness'], ARRAY['still'], 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('deep-002', 'Are you proud of who you''re becoming?', 'becoming', 3, 'Think about your trajectory lately, not just how you feel in this moment.', ARRAY['self-growth', 'identity', 'pride'], ARRAY['mirrors'], 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('deep-003', 'Did you listen to your intuition recently?', 'intuition', 2, '"Recently" means the past week or so — and listening means you noticed and acted on it.', ARRAY['intuition', 'decision-making', 'self-trust'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('deep-004', 'Is there something you need to forgive yourself for?', 'forgiveness', 3, 'Any size counts, from a small slip to something you''ve carried for years.', ARRAY['forgiveness', 'self-compassion', 'guilt'], ARRAY['shadows'], 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('deep-005', 'Are you being honest with yourself?', 'honesty', 3, 'Answer for the parts of life you actually think about — no one audits every corner at once.', ARRAY['honesty', 'self-awareness', 'truth'], ARRAY['mirrors', 'shadows'], 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('deep-006', 'Did you make time for silence today?', 'stillness', 1, 'Silence means no screens or conversation — even a few quiet minutes count.', ARRAY['silence', 'solitude', 'mindfulness'], ARRAY['still'], 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('deep-007', 'Are you holding onto something you should let go?', 'letting_go', 3, 'Could be a grudge, a belief, a habit, or a person — you decide what fits.', ARRAY['letting-go', 'attachment', 'release'], ARRAY['shadows'], 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('deep-008', 'Did you feel grateful for something small?', 'gratitude', 1, 'Small means easy to overlook, not a big event.', ARRAY['gratitude', 'small-joys', 'appreciation'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('deep-009', 'Are you where you thought you''d be at this point in life?', 'perspective', 3, 'Compare to how you imagined things a few years back, not to anyone else''s timeline.', ARRAY['expectations', 'life-path', 'perspective'], ARRAY['crossroads'], 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('deep-010', 'Did you choose kindness over being right?', 'kindness', 2, 'A moment you could have corrected or won an argument, and chose warmth instead.', ARRAY['kindness', 'ego', 'relationships'], '{}', 'seed', 'published', NULL);
