insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('light-001', 'Did you laugh out loud today?', 'humor', 1, 'A real laugh out loud counts — a smile or silent chuckle doesn''t.', ARRAY['laughter', 'humor', 'joy'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('light-002', 'Have you danced when nobody was watching?', 'spontaneous', 1, 'Any kind of movement counts, even a quick shimmy in the kitchen.', ARRAY['dancing', 'spontaneity', 'play'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('light-003', 'Did you eat something delicious?', 'delight', 1, 'Delicious by your own standard, however simple or fancy.', ARRAY['food', 'pleasure', 'everyday-life'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('light-004', 'Have you taken a really good nap recently?', 'comfort', 1, '"Recently" means anytime in the last week or so.', ARRAY['rest', 'sleep', 'comfort'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('light-005', 'Did you sing in the shower?', 'playful', 1, 'Has to be an actual shower — humming elsewhere doesn''t count.', ARRAY['singing', 'playfulness', 'music'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('light-006', 'Have you worn your favorite outfit this week?', 'joy', 1, 'Your current favorite, not necessarily an all-time one.', ARRAY['style', 'self-expression', 'joy'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('light-007', 'Did you pet a dog or cat today?', 'warmth', 1, 'Yours or someone else''s — even a quick pet counts.', ARRAY['pets', 'animals', 'warmth'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('light-008', 'Have you watched the clouds go by?', 'peace', 1, 'No specific timeframe — today or any day you remember counts.', ARRAY['nature', 'daydreaming', 'peace'], ARRAY['still'], 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('light-009', 'Did you treat yourself to something nice?', 'indulgence', 1, 'Any size treat counts, from a coffee to something bigger.', ARRAY['self-care', 'indulgence', 'treats'], '{}', 'seed', 'published', NULL);
