insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('social-001', 'Did you tell someone you appreciate them?', 'appreciation', 2, 'In person, text, or any way you told them — as long as they knew.', ARRAY['appreciation', 'gratitude', 'relationships'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('social-002', 'Have you called a friend just to chat?', 'friendship', 1, 'A phone or video call, not just texting — voice counts either way.', ARRAY['friendship', 'connection', 'communication'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('social-003', 'Did you make someone smile today?', 'warmth', 1, 'Doesn''t have to be on purpose — you just need to know it happened.', ARRAY['kindness', 'relationships', 'warmth'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('social-004', 'Have you hugged someone you love?', 'love', 1, 'Any timeframe you can recall, not just today.', ARRAY['love', 'affection', 'touch'], ARRAY['embers'], 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('social-005', 'Did you really listen when someone talked to you?', 'listening', 2, '"Really listen" means not planning your response or checking your phone.', ARRAY['listening', 'attention', 'relationships'], '{}', 'seed', 'published', NULL);
