insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('pop-001', 'Have you watched a movie that made you cry?', 'resonance', 1, 'Any timeframe, any movie — tearing up counts as crying.', ARRAY['movies', 'emotions', 'storytelling'], '{}', 'seed', 'published', NULL);
