insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('trivia-001', 'Can you name all the planets in order?', 'knowledge', 2, 'The eight recognized planets — Pluto is optional either way.', ARRAY['space', 'trivia', 'knowledge'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('trivia-002', 'Do you know your blood type?', 'knowledge', 1, NULL, ARRAY['health', 'trivia', 'self-knowledge'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('trivia-003', 'Have you ever seen a shooting star?', 'wonder', 1, 'A meteor you took to be a shooting star counts, confirmed or not.', ARRAY['nature', 'wonder', 'sky'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('trivia-004', 'Can you fold a paper crane?', 'skill', 2, 'From memory, without looking up the steps.', ARRAY['origami', 'skill', 'craft'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('trivia-005', 'Do you know how to read a map without GPS?', 'resourcefulness', 2, 'A paper map or general sense of direction — not memorizing every road.', ARRAY['navigation', 'skill', 'resourcefulness'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('trivia-006', 'Have you ever grown something from a seed?', 'patience', 1, NULL, ARRAY['gardening', 'patience', 'nature'], '{}', 'seed', 'published', NULL);
