insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-001', 'Did you drink enough water today?', 'health', 1, 'Go by what feels like enough for your body, not a specific number of glasses.', ARRAY['hydration', 'health', 'habits'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-002', 'Have you stretched your body?', 'health', 1, 'Any stretching counts, formal or just reaching before getting up.', ARRAY['exercise', 'body', 'health'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-003', 'Did you get some fresh air?', 'nature', 1, 'Even a few minutes outside or by an open window counts.', ARRAY['nature', 'outdoors', 'fresh-air'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-004', 'Have you taken a deep breath on purpose?', 'mindfulness', 1, NULL, ARRAY['breathing', 'mindfulness', 'calm'], ARRAY['still'], 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-005', 'Did you put your phone down for an hour?', 'balance', 2, 'Counts whether it was one continuous hour or added up across the day.', ARRAY['technology', 'balance', 'attention'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-006', 'Have you done something just for yourself?', 'selfcare', 2, 'Anything chosen purely for your own enjoyment, no matter how small.', ARRAY['self-care', 'priorities', 'rest'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-007', 'Did you go to bed at a reasonable time?', 'discipline', 2, 'Reasonable by your own standard and schedule, not a fixed hour.', ARRAY['sleep', 'discipline', 'routine'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-008', 'Have you moved your body today?', 'health', 1, 'Any movement counts — a walk or chores, not just formal exercise.', ARRAY['exercise', 'body', 'health'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-009', 'Did you eat a vegetable?', 'nourishment', 1, NULL, ARRAY['food', 'nutrition', 'health'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-010', 'Have you looked up from your screen at the sky?', 'nature', 1, NULL, ARRAY['nature', 'technology', 'attention'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-011', 'Did you wake up feeling rested?', 'rest', 1, NULL, ARRAY['sleep', 'rest', 'energy'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-012', 'Have you taken a walk outside today?', 'nature', 1, 'Any length counts, from a quick loop around the block to a longer walk.', ARRAY['walking', 'nature', 'exercise'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-013', 'Did you eat a home-cooked meal?', 'nourishment', 1, 'Made by you or anyone in your household — reheated takeout doesn''t count.', ARRAY['food', 'cooking', 'nourishment'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-014', 'Have you said no to something that drains you?', 'boundaries', 2, 'Could be a request, an obligation, or your own habit — any "no" counts.', ARRAY['boundaries', 'energy', 'self-protection'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-015', 'Did you spend less than an hour on social media?', 'balance', 2, NULL, ARRAY['social-media', 'balance', 'technology'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-016', 'Have you cleaned or organized a space today?', 'discipline', 1, 'Any space counts, even a single drawer or your desk.', ARRAY['organization', 'home', 'discipline'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-017', 'Did you take your medication or vitamins?', 'health', 1, NULL, ARRAY['health', 'routine', 'self-care'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-018', 'Have you listened to your body''s signals?', 'mindfulness', 2, 'Signals like hunger, fatigue, or tension — noticing them is enough, acting isn''t required.', ARRAY['body', 'mindfulness', 'health'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-019', 'Did you do something that made you feel strong?', 'strength', 2, 'Physical, mental, or emotional strength all count.', ARRAY['strength', 'confidence', 'body'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-020', 'Have you journaled or reflected in writing?', 'reflection', 2, 'Any format counts, from a full journal entry to a few scribbled notes.', ARRAY['journaling', 'reflection', 'writing'], ARRAY['mirrors'], 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-021', 'Did you avoid comparing yourself to others today?', 'honesty', 3, 'Noticing a comparison and letting it go counts as avoiding it.', ARRAY['comparison', 'self-acceptance', 'honesty'], ARRAY['mirrors'], 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-022', 'Have you created something today?', 'creation', 2, 'Anything you made counts, from a meal to a piece of art.', ARRAY['creativity', 'making', 'expression'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-023', 'Did you rest without guilt?', 'rest', 2, 'Any kind of rest counts — the point is the absence of guilt, not the activity.', ARRAY['rest', 'guilt', 'self-care'], ARRAY['still'], 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('wellness-024', 'Have you spent time in nature this week?', 'nature', 1, 'A park or a backyard counts — it doesn''t have to be wilderness.', ARRAY['nature', 'outdoors', 'wellbeing'], '{}', 'seed', 'published', NULL);
