insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('creativity-001', 'Did you have a vivid dream last night?', 'dreams', 1, 'Vivid means detailed or memorable, not necessarily pleasant.', ARRAY['dreams', 'sleep', 'imagination'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('creativity-002', 'Have you written something creative recently?', 'creation', 2, '"Recently" means the last few weeks — a few lines count, not just finished pieces.', ARRAY['writing', 'creativity', 'expression'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('creativity-003', 'Did you make something with your hands today?', 'craft', 2, 'Anything physical counts, from a meal to a repair.', ARRAY['craft', 'making', 'creativity'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('creativity-004', 'Have you had a new idea that excited you?', 'inspiration', 1, 'No timeframe — any idea you can remember getting excited about.', ARRAY['ideas', 'inspiration', 'excitement'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('creativity-005', 'Did you daydream today?', 'imagination', 1, NULL, ARRAY['daydreaming', 'imagination', 'mind-wandering'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('creativity-006', 'Have you tried a new creative medium?', 'experimentation', 2, 'Any art form you haven''t tried before, however briefly.', ARRAY['creativity', 'experimentation', 'art'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('creativity-007', 'Did you take a photo that tells a story?', 'expression', 2, 'It just needs to capture a moment or feeling, not a whole narrative.', ARRAY['photography', 'storytelling', 'expression'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('creativity-008', 'Have you been inspired by something unexpected?', 'inspiration', 1, NULL, ARRAY['inspiration', 'surprise', 'creativity'], '{}', 'seed', 'published', NULL);
