insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('growth-001', 'Did you learn something new today?', 'learning', 1, 'Any size counts, from a small fact to a real insight.', ARRAY['learning', 'curiosity', 'growth'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('growth-002', 'Have you taken a step toward a goal this week?', 'ambition', 2, 'Any size step counts, even a small one.', ARRAY['goals', 'ambition', 'progress'], ARRAY['compass'], 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('growth-003', 'Did you step outside your comfort zone?', 'fear', 2, 'Any size counts — it''s about the discomfort, not the scale of the act.', ARRAY['comfort-zone', 'courage', 'growth'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('growth-004', 'Have you asked for feedback recently?', 'feedback', 2, '"Recently" means the last few weeks or so.', ARRAY['feedback', 'growth', 'vulnerability'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('growth-005', 'Did you fail at something and try again?', 'grit', 3, 'Any size of failure counts, as long as you tried again after.', ARRAY['failure', 'perseverance', 'grit'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('growth-006', 'Have you read something that challenged your thinking?', 'curiosity', 2, 'No timeframe — books, articles, or anything else you''ve read.', ARRAY['reading', 'perspective', 'learning'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('growth-007', 'Did you practice a skill you''re developing?', 'discipline', 2, NULL, ARRAY['practice', 'skill', 'discipline'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('growth-008', 'Have you invested in your future self?', 'ambition', 2, 'Time, money, or effort — any investment in where you''re headed counts.', ARRAY['future', 'ambition', 'investment'], ARRAY['compass'], 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('growth-009', 'Did you have a productive day?', 'discipline', 1, 'Productive by your own definition, not anyone else''s checklist.', ARRAY['productivity', 'discipline', 'work'], '{}', 'seed', 'published', NULL);
insert into public.questions (slug, text, vibe, difficulty, fine_print, tags, related_gardens, source, status, owner_id) values ('growth-010', 'Have you mentored or taught someone?', 'generosity', 2, 'Formal or informal — showing someone how to do something counts.', ARRAY['mentorship', 'teaching', 'generosity'], '{}', 'seed', 'published', NULL);
